   349|/**
   350| * Calls the backend auth-diagnostic endpoint with the rejected bearer to obtain
   351| * the structured reason Supabase rejected the session. NEVER logs the bearer.
   352| */
   353|async function probeBackendAuthDiagnostic(
   354|  ownerAIEndpoint: string,
   355|  accessToken: string,
   356|  requestLabel: string,
   357|): Promise<IVXOwnerAIAuthDiagnosticSnapshot> {
   358|  const diagnosticUrl = buildAuthDiagnosticUrlFromEndpoint(ownerAIEndpoint);
   359|  const fetchedAt = new Date().toISOString();
   360|  const empty: IVXOwnerAIAuthDiagnosticSnapshot = {
   361|    ok: null,
   362|    rootCause: null,
   363|    tokenPresent: null,
   364|    tokenLength: null,
   365|    issuerMatchesBackendProject: null,
   366|    expectedIssuer: null,
   367|    tokenIssuer: null,
   368|    tokenExpired: null,
   369|    secondsUntilExpiry: null,
   370|    supabaseUserFound: null,
   371|    supabaseErrorMessage: null,
   372|    ownerEmailAllowlisted: null,
   373|    authenticatedEmailMasked: null,
   374|    allowlistConfigured: null,
   375|    backendSupabaseUrl: null,
   376|    backendProjectRef: null,
   377|    serverTimeIso: null,
   378|    diagnosticHttpStatus: null,
   379|    diagnosticFetchError: null,
   380|    fetchedAt,
   381|  };
   382|  if (!diagnosticUrl) {
   383|    const snapshot = { ...empty, diagnosticFetchError: 'Could not derive diagnostic URL from owner AI endpoint.' };
   384|    lastOwnerAIAuthDiagnostic = snapshot;
   385|    return snapshot;
   386|  }
   387|  try {
   388|    const response = await fetchWithTimeout(diagnosticUrl, {
   389|      method: 'POST',
   390|      headers: {
   391|        'Content-Type': 'application/json',
   392|        Authorization: `Bearer ${accessToken}`,
   393|      },
   394|      body: '{}',
   395|    }, 10_000);
   396|    const status = response.status;
   397|    let parsed: unknown = null;
   398|    try {
   399|      parsed = await response.json();
   400|    } catch {
   401|      parsed = null;
   402|    }
   403|    const record = isRecord(parsed) ? parsed : {};
   404|    const backend = isRecord(record.backend) ? record.backend : {};
   405|    const claims = isRecord(record.claims) ? record.claims : {};
   406|    const checks = isRecord(record.checks) ? record.checks : {};
   407|    const supabaseLookup = isRecord(record.supabaseLookup) ? record.supabaseLookup : {};
   408|    const ownerAllowlist = isRecord(record.ownerAllowlist) ? record.ownerAllowlist : {};
   409|    const snapshot: IVXOwnerAIAuthDiagnosticSnapshot = {
   410|      ok: typeof record.ok === 'boolean' ? record.ok : null,
   411|      rootCause: typeof record.rootCause === 'string' ? record.rootCause : null,
   412|      tokenPresent: typeof record.tokenPresent === 'boolean' ? record.tokenPresent : null,
   413|      tokenLength: typeof record.tokenLength === 'number' ? record.tokenLength : null,
   414|      issuerMatchesBackendProject: typeof checks.issuerMatchesBackendProject === 'boolean' ? checks.issuerMatchesBackendProject : null,
   415|      expectedIssuer: typeof checks.expectedIssuer === 'string' ? checks.expectedIssuer : null,
   416|      tokenIssuer: typeof claims.iss === 'string' ? claims.iss : null,
   417|      tokenExpired: typeof checks.tokenExpired === 'boolean' ? checks.tokenExpired : null,
   418|      secondsUntilExpiry: typeof checks.secondsUntilExpiry === 'number' ? checks.secondsUntilExpiry : null,
   419|      supabaseUserFound: typeof supabaseLookup.userFound === 'boolean' ? supabaseLookup.userFound : null,
   420|      supabaseErrorMessage: typeof supabaseLookup.errorMessage === 'string' ? supabaseLookup.errorMessage : null,
   421|      ownerEmailAllowlisted: typeof checks.ownerEmailAllowlisted === 'boolean' ? checks.ownerEmailAllowlisted : null,
   422|      authenticatedEmailMasked: typeof ownerAllowlist.authenticatedEmailMasked === 'string' ? ownerAllowlist.authenticatedEmailMasked : null,
   423|      allowlistConfigured: typeof ownerAllowlist.allowlistConfigured === 'boolean' ? ownerAllowlist.allowlistConfigured : null,
   424|      backendSupabaseUrl: typeof backend.supabaseUrl === 'string' ? backend.supabaseUrl : null,
   425|      backendProjectRef: typeof backend.supabaseProjectRef === 'string' ? backend.supabaseProjectRef : null,
   426|      serverTimeIso: typeof backend.serverTimeIso === 'string' ? backend.serverTimeIso : null,
   427|      diagnosticHttpStatus: status,
   428|      diagnosticFetchError: null,
   429|      fetchedAt,
   430|    };
   431|    console.log(`[IVXAIRequestService] ${requestLabel} backend auth diagnostic result:`, snapshot);
   432|    lastOwnerAIAuthDiagnostic = snapshot;
   433|    return snapshot;
   434|  } catch (error) {
   435|    const snapshot: IVXOwnerAIAuthDiagnosticSnapshot = {
   436|      ...empty,
   437|      diagnosticFetchError: error instanceof Error ? error.message : 'unknown',
   438|    };
   439|    console.log(`[IVXAIRequestService] ${requestLabel} backend auth diagnostic fetch failed:`, snapshot.diagnosticFetchError);
   440|    lastOwnerAIAuthDiagnostic = snapshot;
   441|    return snapshot;
   442|  }
