// ─── VERCEL TOOL ────────────────────────────────────────────────────────

export async function handleVercelStatus(): Promise<Response> {
  try {
    const configured = (process.env.VERCEL_TOKEN ?? '').trim().length > 0;
    if (!configured) {
      return publicJson({
        ok: false,
        error: 'VERCEL_TOKEN not configured — Vercel tool is inactive',
